// GADO.MIN.JS - Improved Pseudo 3D
const GADO = {
  version: "2.4",
  canvas: null,
  ctx: null,
  camera: { x: 0, y: -20, z: 320, rotX: 0.4, rotY: 0.6 },
  cube: { rotX: 0, rotY: 0 },
  keys: {},
  mouse: { down: false },
  particles: [],

  init(canvasId = 'game') {
    this.canvas = document.getElementById(canvasId);
    if (!this.canvas) {
      this.canvas = document.createElement('canvas');
      this.canvas.width = 960;
      this.canvas.height = 640;
      document.body.appendChild(this.canvas);
    }
    this.ctx = this.canvas.getContext('2d');
    this.setupControls();
    this.gameLoop();
    console.log('%cGADO Pseudo-3D v' + this.version + ' Improved ✅', 'color:#0f0;font-size:20px');
  },

  setupControls() {
    window.addEventListener('keydown', e => this.keys[e.key.toLowerCase()] = true);
    window.addEventListener('keyup', e => this.keys[e.key.toLowerCase()] = false);

    this.canvas.addEventListener('mousedown', () => this.mouse.down = true);
    this.canvas.addEventListener('mouseup', () => this.mouse.down = false);
    this.canvas.addEventListener('mousemove', e => {
      if (this.mouse.down) {
        this.camera.rotY += e.movementX * 0.006;
        this.camera.rotX += e.movementY * 0.006;
      }
    });
  },

  project(x, y, z) {
    const dist = 650 / (z + this.camera.z);
    return {
      x: this.canvas.width/2 + (x - this.camera.x) * dist,
      y: this.canvas.height/2 + (y - this.camera.y) * dist,
      scale: dist
    };
  },

  spawnExplosion(x=480, y=300) {
    for (let i = 0; i < 200; i++) {
      this.particles.push({
        x, y,
        vx: Math.random()*20-10,
        vy: Math.random()*20-14,
        life: 90,
        size: 6 + Math.random()*10,
        color: `hsl(${Math.random()*80},100%,65%)`
      });
    }
  },

  update() {
    if (this.keys['a'] || this.keys['arrowleft']) this.camera.x -= 8;
    if (this.keys['d'] || this.keys['arrowright']) this.camera.x += 8;
    if (this.keys['w'] || this.keys['arrowup']) this.camera.z -= 12;
    if (this.keys['s'] || this.keys['arrowdown']) this.camera.z += 12;
    if (this.keys[' ']) { this.spawnExplosion(); this.keys[' '] = false; }

    this.cube.rotX += 0.015;
    this.cube.rotY += 0.022;

    this.particles = this.particles.filter(p => {
      p.x += p.vx; p.y += p.vy; p.vy += 0.4; p.life--; p.size *= 0.96; return p.life > 5;
    });
  },

  drawCube() {
    const s = 110;
    let pts = [];
    for (let x=-1; x<=1; x+=2)
      for (let y=-1; y<=1; y+=2)
        for (let z=-1; z<=1; z+=2) {
          let px = x*s, py = y*s, pz = z*s;

          // Rotate X
          let rx = py * Math.cos(this.cube.rotX) - pz * Math.sin(this.cube.rotX);
          let rz = py * Math.sin(this.cube.rotX) + pz * Math.cos(this.cube.rotX);
          py = rx; pz = rz;

          // Rotate Y
          let ry = px * Math.cos(this.cube.rotY) - pz * Math.sin(this.cube.rotY);
          pz = px * Math.sin(this.cube.rotY) + pz * Math.cos(this.cube.rotY);
          px = ry;

          pts.push(this.project(px, py, pz));
        }

    this.ctx.strokeStyle = '#00ffff';
    this.ctx.lineWidth = 6;
    const edges = [[0,1],[1,3],[3,2],[2,0],[4,5],[5,7],[7,6],[6,4],[0,4],[1,5],[2,6],[3,7]];

    edges.forEach(([a,b]) => {
      this.ctx.shadowColor = '#00ffff';
      this.ctx.shadowBlur = 15;
      this.ctx.beginPath();
      this.ctx.moveTo(pts[a].x, pts[a].y);
      this.ctx.lineTo(pts[b].x, pts[b].y);
      this.ctx.stroke();
    });
    this.ctx.shadowBlur = 0;
  },

  render() {
    this.ctx.fillStyle = '#050518';
    this.ctx.fillRect(0, 0, this.canvas.width, this.canvas.height);

    this.drawCube();

    this.particles.forEach(p => {
      this.ctx.globalAlpha = p.life / 100;
      this.ctx.fillStyle = p.color;
      this.ctx.fillRect(p.x, p.y, p.size, p.size);
    });
    this.ctx.globalAlpha = 1;

    this.ctx.fillStyle = '#0f0';
    this.ctx.font = 'bold 32px Arial';
    this.ctx.fillText('GADO Pseudo-3D', 40, 60);
  },

  gameLoop() {
    this.update();
    this.render();
    requestAnimationFrame(() => this.gameLoop());
  }
};

window.GADO = GADO;
